import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getResumes, uploadResume, deleteResume, searchResumes } from '../services/api';

function ScoreBadge({ score }) {
  const color = score >= 70 ? '#10b981' : score >= 40 ? '#f59e0b' : '#ef4444';
  return (
    <div style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 52, height: 52, borderRadius: '50%', border: `3px solid ${color}`, color, fontWeight: 700, fontSize: 14 }}>
      {score}%
    </div>
  );
}

export default function Resumes() {
  const { jobId } = useParams();
  const [resumes, setResumes] = useState([]);
  const [form, setForm] = useState({ candidateName: '', email: '', file: null });
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);
  const [show, setShow] = useState(false);

  const load = () => getResumes(jobId).then(r => setResumes(r.data));
  useEffect(() => { load(); }, [jobId]);

  const handleUpload = async (e) => {
    e.preventDefault();
    if (!form.file) return;
    const fd = new FormData();
    fd.append('file', form.file);
    fd.append('jobId', jobId);
    fd.append('candidateName', form.candidateName);
    fd.append('email', form.email);
    setLoading(true);
    try { await uploadResume(fd); setForm({ candidateName: '', email: '', file: null }); setShow(false); load(); }
    finally { setLoading(false); }
  };

  const handleSearch = async () => {
    if (!search.trim()) { load(); return; }
    const r = await searchResumes(search);
    setResumes(r.data);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete resume?')) { await deleteResume(id); load(); }
  };

  return (
    <div className="page">
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
        <h2>Candidates</h2>
        <button className="btn-primary" onClick={() => setShow(!show)}>{show ? 'Cancel' : '+ Upload Resume'}</button>
      </div>

      {show && (
        <div className="card" style={{ marginBottom: 24 }}>
          <h2>Upload Resume (PDF)</h2>
          <form onSubmit={handleUpload} style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            <input placeholder="Candidate Name" value={form.candidateName} onChange={e => setForm({...form, candidateName: e.target.value})} required />
            <input placeholder="Candidate Email" type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} required />
            <input type="file" accept=".pdf" onChange={e => setForm({...form, file: e.target.files[0]})} required />
            <button className="btn-success" type="submit" style={{ alignSelf: 'flex-start' }} disabled={loading}>
              {loading ? 'Processing...' : 'Upload & Analyze'}
            </button>
          </form>
        </div>
      )}

      <div style={{ display: 'flex', gap: 10, marginBottom: 20 }}>
        <input placeholder="Search by name..." value={search} onChange={e => setSearch(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSearch()} style={{ flex: 1 }} />
        <button className="btn-primary" onClick={handleSearch}>Search</button>
        <button style={{ background: '#e5e7eb', borderRadius: 6, border: 'none', padding: '10px 16px', cursor: 'pointer' }} onClick={() => { setSearch(''); load(); }}>Reset</button>
      </div>

      {resumes.length === 0 ? (
        <div className="card"><p style={{ color: '#999' }}>No resumes uploaded yet.</p></div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          {resumes.map((r, i) => (
            <div key={r.id} className="card" style={{ display: 'flex', gap: 16, alignItems: 'flex-start', borderLeft: `4px solid ${r.atsScore >= 70 ? '#10b981' : r.atsScore >= 40 ? '#f59e0b' : '#ef4444'}` }}>
              <div style={{ fontWeight: 700, fontSize: 18, color: '#aaa', width: 28, flexShrink: 0, paddingTop: 14 }}>#{i + 1}</div>
              <ScoreBadge score={Math.round(r.atsScore)} />
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 16 }}>{r.candidateName}</div>
                <div style={{ color: '#666', fontSize: 13 }}>{r.email} · {r.fileName}</div>
                <div style={{ marginTop: 8, fontSize: 13 }}>
                  <strong>Matched Skills: </strong>
                  {r.extractedSkills ? r.extractedSkills.split(',').map((s, i) => (
                    <span key={i} style={{ background: '#d1fae5', color: '#065f46', borderRadius: 10, padding: '2px 8px', fontSize: 12, marginRight: 4 }}>{s.trim()}</span>
                  )) : <span style={{ color: '#999' }}>None detected</span>}
                </div>
              </div>
              <div style={{ flexShrink: 0, display: 'flex', alignItems: 'center', gap: 10 }}>
                <span style={{ fontSize: 12, color: '#888' }}>{new Date(r.uploadedAt).toLocaleDateString()}</span>
                <button className="btn-danger" style={{ fontSize: 12, padding: '6px 10px' }} onClick={() => handleDelete(r.id)}>Delete</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
